CREATE TRIGGER IF NOT EXISTS "first_setup_complete_on_credential" AFTER INSERT ON "account" WHEN NEW."providerId" = 'credential' BEGIN UPDATE "first_setup" SET "status" = 'completed', "claim_token_hash" = NULL, "completed_at" = CAST((julianday('now') - 2440587.5) * 86400000 AS INTEGER) WHERE "id" = 1 AND "status" = 'claimed' AND "claimed_user_id" = NEW."userId" AND EXISTS (SELECT 1 FROM "user" WHERE "id" = NEW."userId" AND "role" = 'admin' AND COALESCE("super_admin", 0) = 1); END;
